module RefModule (  
    input wire clk,  
    input wire reset,  
    input wire [3:0] data_in,  
    output reg [3:0] modulated_out  
);  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            modulated_out <= 4'b0000;  
        else  
            modulated_out <= data_in;  
    end  
endmodule
